function pf_acf_houzez_gallery($post_id = null) {

    if (!$post_id) $post_id = get_the_ID();

    $media = get_field('media', $post_id);
    if (empty($media['images'])) return '';

    $images = [];

    foreach ($media['images'] as $index => $img) {

        $url = $img['original_url'] ?? '';
        if (!$url) continue;

        // Try to get attachment ID
        $attachment_id = attachment_url_to_postid($url);

        if ($attachment_id) {

            if ($index === 0 && !has_post_thumbnail($post_id)) {
                set_post_thumbnail($post_id, $attachment_id);
            }

            $images[] = [
                'url' => wp_get_attachment_image_url($attachment_id, 'large'),
                'alt' => get_post_meta($attachment_id, '_wp_attachment_image_alt', true)
            ];

        } else {

            // If not found in media library, just use original URL
            $images[] = [
                'url' => esc_url($url),
                'alt' => ''
            ];
        }
    }

    if (!$images) return '';

    $total  = count($images);
    $first  = $images[0] ?? null;
    $second = $images[1] ?? null;
    $third  = $images[2] ?? null;

    ob_start(); ?>

    <div class="pf-houzez-grid">

        <?php if ($first): ?>
        <div class="pf-big" data-index="0">
            <img src="<?php echo esc_url($first['url']); ?>" alt="">
            <span class="pf-count"><?php echo $total; ?> Photos</span>
        </div>
        <?php endif; ?>

        <div class="pf-right">
            <?php foreach([$second, $third] as $i => $img): 
                if (!$img) continue;
            ?>
            <div class="pf-small" data-index="<?php echo $i+1; ?>">
                <img src="<?php echo esc_url($img['url']); ?>" alt="">
            </div>
            <?php endforeach; ?>
        </div>

    </div>

    <div class="pf-lightbox" id="pfLightbox">
        <span class="pf-close">&times;</span>
        <span class="pf-prev">&#10094;</span>
        <span class="pf-next">&#10095;</span>
        <img id="pfMain">
        <div id="pfThumbs"></div>
    </div>

    <script>
    window.pfGalleryData = <?php echo wp_json_encode($images); ?>;
    </script>

    <?php
    return ob_get_clean();
}

add_shortcode('pf_houzez_gallery', function(){
    return pf_acf_houzez_gallery(get_the_ID());
});

add_action('wp_footer', function() { ?>
<script>
document.addEventListener("DOMContentLoaded", function() {

    let data = window.pfGalleryData || [];
    if (!data.length) return;

    let lb = document.getElementById("pfLightbox");
    let main = document.getElementById("pfMain");
    let thumbs = document.getElementById("pfThumbs");
    let current = 0;

    document.querySelectorAll(".pf-big, .pf-small").forEach(box => {
        box.addEventListener("click", () => {
            current = parseInt(box.dataset.index);
            openLB();
        });
    });

    function openLB() {
        lb.style.display = "flex";
        renderThumbs();
        loadMain();
    }

    function loadMain() {
        main.src = data[current].url;
        thumbs.querySelectorAll("img").forEach((t,i)=>{
            t.classList.toggle("active", i === current);
        });
    }

    function renderThumbs() {
        thumbs.innerHTML = "";
        data.forEach((img, i) => {
            let t = document.createElement("img");
            t.src = img.url;
            t.onclick = () => { current = i; loadMain(); };
            thumbs.appendChild(t);
        });
    }

    document.querySelector(".pf-prev").onclick = () => {
        current = (current - 1 + data.length) % data.length;
        loadMain();
    };

    document.querySelector(".pf-next").onclick = () => {
        current = (current + 1) % data.length;
        loadMain();
    };

    document.querySelector(".pf-close").onclick = () => {
        lb.style.display = "none";
    };
});
</script>

