function property_full_title_elementor_safe()
{
    $post = get_post();
    if (!$post) return '';

    $post_id = $post->ID;

    /* ===== TYPE ===== */
    $type = strtoupper(get_field('type', $post_id) ?: 'PROPERTY');

    /* ===== PRICE ===== */
    $price = get_field('price', $post_id);
    $transaction = 'FOR SALE';
    $amount = 0;

    if (is_array($price)) {
        if (($price['type'] ?? '') === 'rent') {
            $transaction = 'FOR RENT';
            $amount = $price['rent_amount'] ?? 0;
        } else {
            $amount = $price['sale_amount'] ?? 0;
        }
    }

    $price_text = $amount ? 'AED ' . number_format((float)$amount) : '';

    /* ===== LOCATION (ONLY MAP BASED) ===== */
    $location = get_field('location', $post_id);

    $lat = $location['coordinates']['lat'] ?? '';
    $lng = $location['coordinates']['lng'] ?? '';

    $map_link = '';
    if ($lat && $lng) {
        $map_link = 'https://www.google.com/maps?q=' . $lat . ',' . $lng;
    }

    /* ===== TITLE ===== */
    $title = "{$type} {$transaction}";
    if ($price_text) {
        $title .= " - {$price_text}";
    }

    /* ===== OUTPUT ===== */
    $html  = '<h5 class="property-full-title">';
    $html .= esc_html($title);

    if ($map_link) {
        $html .= ' <a href="' . esc_url($map_link) . '" target="_blank" class="property-map-link"> View on Map</a>';
    }

    $html .= '</h5>';

    return $html;
}

