add_action('save_post', function ( $post_id, $post, $update ) {

    // ✅ sirf houzez property
    if ( $post->post_type !== 'houzez_property' ) return;

    // autosave / revision skip
    if ( defined('DOING_AUTOSAVE') && DOING_AUTOSAVE ) return;
    if ( wp_is_post_revision( $post_id ) ) return;

    // 🔑 ACF value late milti hai, is liye meta se lo
    $agent_name = get_post_meta( $post_id, 'agent_name_acf', true );
    $agent_name = trim( $agent_name );

    if ( empty( $agent_name ) ) return;

    global $wpdb;

    // 🔍 agent search
    $agent_id = $wpdb->get_var( $wpdb->prepare(
        "SELECT ID FROM {$wpdb->posts}
         WHERE post_type = 'houzez_agent'
         AND post_status = 'publish'
         AND post_title = %s
         LIMIT 1",
        $agent_name
    ));

    if ( ! $agent_id ) return;

    // ✅ FORCE display option
    update_post_meta( $post_id, 'fave_agent_display_option', 'agent_info' );

    // ✅ REAL agent attach (Houzez compatible)
    update_post_meta( $post_id, 'fave_property_agent', intval( $agent_id ) );

}, 20, 3 );

