function pf_property_image_dots_slider($post_id = null) {

    if (!$post_id) $post_id = get_the_ID();

    $media = get_field('media', $post_id);
    if (empty($media['images'])) return '';

    $images = [];

    foreach ($media['images'] as $index => $img) {

        $url = $img['original_url'] ?? '';
        if (!$url) continue;

        $attachment_id = attachment_url_to_postid($url);

        if ($attachment_id) {

            if ($index === 0 && !has_post_thumbnail($post_id)) {
                set_post_thumbnail($post_id, $attachment_id);
            }

            $images[] = wp_get_attachment_image_url($attachment_id, 'large');

        } else {

            // Use original URL if not in media library
            $images[] = esc_url($url);
        }
    }

    if (!$images) return '';

    $total = count($images);

    ob_start(); ?>

    <div class="pf-slider" data-total="<?php echo esc_attr($total); ?>">
        <div class="pf-slider-track">
            <?php foreach ($images as $img): ?>
                <div class="pf-slide">
                    <img src="<?php echo esc_url($img); ?>" alt="">
                </div>
            <?php endforeach; ?>
        </div>

        <div class="pf-dots">
            <?php foreach ($images as $i => $img): ?>
                <span class="pf-dot <?php echo $i === 0 ? 'active' : ''; ?>" data-index="<?php echo $i; ?>"></span>
            <?php endforeach; ?>
        </div>

        <div class="pf-count">
            <span class="pf-camera">📷</span>
            <span class="pf-number"><?php echo $total; ?></span>
        </div>
    </div>

    <?php
    return ob_get_clean();
}

