});

function pf_set_featured_from_acf_url($post_id, $image_index = 0) {

    if (wp_is_post_revision($post_id) || wp_is_post_autosave($post_id)) {
        return;
    }

    $media = get_field('media', $post_id);
    if (empty($media['images'])) return;

    $img_data = $media['images'][$image_index] ?? null;
    if (!$img_data) return;

    // Prefer original to avoid watermark duplication
    $url = $img_data['original_url'] ?: $img_data['watermarked_url'];
    if (!$url) return;

    // 🔥 Create unique filename
    $ext  = pathinfo(parse_url($url, PHP_URL_PATH), PATHINFO_EXTENSION);
    $name = 'pf-' . md5($url) . '.' . $ext;

    // Already attached to this post?
    $existing = get_post_thumbnail_id($post_id);
    if ($existing) return;

    // Download image
    $response = wp_remote_get($url);
    if (is_wp_error($response)) return;

    $body = wp_remote_retrieve_body($response);
    if (!$body) return;

    // Upload uniquely
    $upload = wp_upload_bits($name, null, $body);
    if ($upload['error']) return;

    $filetype = wp_check_filetype($upload['file'], null);

    $attachment = [
        'post_mime_type' => $filetype['type'],
        'post_title'     => sanitize_file_name($name),
        'post_status'    => 'inherit'
    ];

    $attachment_id = wp_insert_attachment($attachment, $upload['file'], $post_id);

    require_once ABSPATH . 'wp-admin/includes/image.php';

    $meta = wp_generate_attachment_metadata($attachment_id, $upload['file']);
    wp_update_attachment_metadata($attachment_id, $meta);

    set_post_thumbnail($post_id, $attachment_id);
}

