function load_agent_properties() {

    $agent_id = intval($_POST['agent_id']);
    $paged    = intval($_POST['page']);

    $q = new WP_Query([
        'post_type'      => 'property',
        'post_status'    => 'publish',
        'posts_per_page' => 6,
        'paged'          => $paged,
        'meta_query'     => [
            [
                'key'     => 'fave_agents',
                'value'   => 'i:' . $agent_id . ';',
                'compare' => 'LIKE'
            ]
        ]
    ]);

    if ($q->have_posts()) {

        while ($q->have_posts()) {
            $q->the_post();

            echo \Elementor\Plugin::$instance
                ->frontend
                ->get_builder_content_for_display(60134, true);
        }

    }

    wp_reset_postdata();
    wp_die();
}


