function agent_infinite_scroll_script() {

    if (!is_singular('houzez_agent')) return;
    ?>

    <script>
    jQuery(function($){

        var canLoad = true;

        function loadProperties() {

            if(!canLoad) return;

            var wrapper = $('#agent-properties-wrapper');
            if(!wrapper.length) return;

            var page    = wrapper.data('page');
            var agentID = wrapper.data('agent');

            canLoad = false;
            $('.loading-properties').show();

            $.ajax({
                url: "<?php echo admin_url('admin-ajax.php'); ?>",
                type: "POST",
                data: {
                    action: "load_agent_properties",
                    agent_id: agentID,
                    page: page
                },
                success: function(response){

                    if($.trim(response) !== ''){
                        $('.agent-properties-grid').append(response);
                        wrapper.data('page', page + 1);
                        canLoad = true;
                    } else {
                        canLoad = false; // no more posts
                    }

                    $('.loading-properties').hide();
                }
            });
        }

        // First load
        loadProperties();

        // Infinite scroll
        $(window).on('scroll', function(){

            if($(window).scrollTop() + $(window).height() >= $(document).height() - 200){
                loadProperties();
            }

        });

    });
    </script>

    <?php
}
